parameters.jsCode:
// Parse the LLM JSON content and explode into 11 items, one per shot prompt.
const raw = $input.first().json.choices[0].message.content;
let parsed;
try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  throw new Error('LLM did not return valid JSON: ' + e.message);
}
if (!parsed.prompts || !Array.isArray(parsed.prompts) || parsed.prompts.length < 11) {
  throw new Error('Expected 11 prompts in LLM response, got ' + (parsed.prompts ? parsed.prompts.length : 0));
}
const sharedNeg = parsed.shared_negative_prompt || '';
const runId = $('Postgres · Insert generation_run').item.json.id;
const sku = $('Postgres · Load product+style').item.json.sku;
const productId = $('Postgres · Load product+style').item.json.product_id;
const taskId = $('Postgres · Load product+style').item.json.task_id;

return parsed.prompts.map((p, idx) => ({
  json: {
    run_id: runId,
    task_id: taskId,
    product_id: productId,
    sku: sku,
    shot_id: p.shot_id,
    shot_type: p.shot_type,
    en_prompt: p.en_prompt,
    negative_prompt: sharedNeg,
    suggested_size: p.suggested_size || '2048x2048',
    ref_image_ids: p.ref_image_ids || [],
    guidance_scale: p.guidance_scale || 5.5,
    seed: p.seed_hint || (Math.floor(Math.random() * 2_000_000_000)),
    idx: idx,
    ref_image_urls: (p.ref_image_ids || []).map(id => {
      if (id.startsWith('scene_ref_')) {
        return `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/refs/scenes/${id}.jpg`;
      }
      return `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/refs/${sku}/${id}.jpg`;
    })
  }
}));

// Compute OSS keys and merge upstream metadata into a single payload for the next nodes.
const incoming = $input.first().json;
const binary = $input.first().binary;
const meta = $('Code · Explode prompts').item.json;
const sku = meta.sku;
const runId = meta.run_id;
const shotId = meta.shot_id;
const idx = meta.idx;
const ossKey = `archive/${sku}/${runId}/${shotId}_${String(idx).padStart(2,'0')}.png`;
const ossThumbKey = `archive/${sku}/${runId}/thumb_${shotId}_${String(idx).padStart(2,'0')}.jpg`;
const arkRequestId = incoming.id || incoming.request_id || '';
const arkUrl = (incoming.data && incoming.data[0] && incoming.data[0].url) || '';

return [{
  json: {
    ...meta,
    ark_request_id: arkRequestId,
    ark_image_url: arkUrl,
    oss_key: ossKey,
    oss_thumb_key: ossThumbKey,
    oss_bucket: 'yfn-content-factory',
    oss_endpoint: 'oss-cn-shanghai.aliyuncs.com',
    oss_url: `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/${ossKey}`,
    oss_thumb_url: `https://yfn-content-factory.oss-cn-shanghai.aliyuncs.com/${ossThumbKey}`,
    generation_cost_cny: 0.30,
    image_bytes: binary && binary.data ? binary.data.fileSize || 0 : 0
  },
  binary: binary
}];

